import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Helper function to get weather emoji based on condition
  // Helper function to get weather emoji based on condition
  const getWeatherEmoji = (condition: string): string => {
    const conditionLower = condition.toLowerCase();
    if (conditionLower.includes('sunny') || conditionLower.includes('clear')) return '☀️';
    if (conditionLower.includes('partly cloudy') || conditionLower.includes('partly')) return '⛅';
    if (conditionLower.includes('cloudy') || conditionLower.includes('cloud') || conditionLower.includes('overcast')) return '☁️';
    if (conditionLower.includes('rainy') || conditionLower.includes('rain')) return '🌧️';
    if (conditionLower.includes('drizzle')) return '🌦️';
    if (conditionLower.includes('snowy') || conditionLower.includes('snow')) return '❄️';
    if (conditionLower.includes('sleet')) return '🌨️';
    if (conditionLower.includes('hail')) return '🌩️';
    if (conditionLower.includes('stormy') || conditionLower.includes('storm')) return '⛈️';
    if (conditionLower.includes('windy') || conditionLower.includes('wind')) return '💨';
    if (conditionLower.includes('foggy') || conditionLower.includes('fog')) return '🌫️';
    return '🌤️'; // Default fallback
  };

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)" align="center">
        {/* Header with city name */}
        <Heading level={1} color="var(--ggui-color-onSurface)">{props.city}</Heading>

        {/* Main weather card */}
        <Card shadow="md" padding="var(--ggui-spacing-8)" radius="lg" style={{ width: '100%', maxWidth: '500px' }}>
          <Stack gap="var(--ggui-spacing-6)" align="center">
            {/* Temperature section */}
            <Stack gap="var(--ggui-spacing-4)" align="center">
              <div style={{ fontSize: '72px', lineHeight: 1 }}>
                {getWeatherEmoji(props.condition ?? '🌤️')}
              </div>
              <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface)" align="center">
                {props.temperature}°{props.unit || 'C'}
              </Text>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)" align="center">
                {props.condition}
              </Text>
            </Stack>

            <Divider orientation="horizontal" margin="var(--ggui-spacing-4)" color="var(--ggui-color-outlineVariant)" />

            {/* Humidity and Wind Speed */}
            <Stack direction="horizontal" gap="var(--ggui-spacing-6)" justify="center" align="center" style={{ width: '100%' }}>
              <Stack gap="var(--ggui-spacing-2)" align="center">
                <Icon name="droplets" size={24} color="var(--ggui-color-primary-600)" />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                <Text variant="label" color="var(--ggui-color-onSurface)">{props.humidity}%</Text>
              </Stack>

              <Divider orientation="vertical" margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant)" />

              <Stack gap="var(--ggui-spacing-2)" align="center">
                <Icon name="wind" size={24} color="var(--ggui-color-primary-600)" />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
                <Text variant="label" color="var(--ggui-color-onSurface)">{props.windSpeed} km/h</Text>
              </Stack>
            </Stack>
          </Stack>
        </Card>

        {/* 5-Day Forecast */}
        {props.forecast && props.forecast.length > 0 && (
          <Card shadow="sm" padding="var(--ggui-spacing-6)" radius="lg" style={{ width: '100%' }}>
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3} color="var(--ggui-color-onSurface)">5-Day Forecast</Heading>
              <Stack direction="horizontal" gap="var(--ggui-spacing-4)" style={{ overflowX: 'auto', justifyContent: 'flex-start', minWidth: 0 }}>
                {props.forecast.map((day, index) => (
                  <Card
                    key={index}
                    shadow="none"
                    border={false}
                    radius="md"
                    style={{
                      background: 'var(--ggui-color-surfaceVariant)',
                      flex: '0 0 auto',
                      minWidth: '100px',
                      textAlign: 'center',
                    }}
                  >
                    <Stack gap="var(--ggui-spacing-2)" align="center">
                      <Text variant="label" color="var(--ggui-color-onSurface)" align="center">
                        {day.day || `Day ${index + 1}`}
                      </Text>
                      <div style={{ fontSize: '32px', lineHeight: 1 }}>
                         {day.icon && typeof day.icon === 'string' && day.icon.length <= 2 ? day.icon : getWeatherEmoji(day.icon ?? day.day ?? '')}
                      </div>
                      <Stack gap="var(--ggui-spacing-1)" align="center">
                        <Text variant="caption" color="var(--ggui-color-onSurface)" align="center">
                          {day.high}°{props.unit || 'C'} / {day.low}°{props.unit || 'C'}
                        </Text>
                      </Stack>
                    </Stack>
                  </Card>
                ))}
              </Stack>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

