import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State for form data
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [selectedFeatures, setSelectedFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation state
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');

  // Email validation regex
  const validateEmail = (value: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(value);
  };

  // Validate step 1 fields
  const isStep1Valid = (): boolean => {
    let isValid = true;
    if (!name.trim()) {
      setNameError('Name is required');
      isValid = false;
    } else {
      setNameError('');
    }

    if (!email.trim()) {
      setEmailError('Email is required');
      isValid = false;
    } else if (!validateEmail(email)) {
      setEmailError('Invalid email format');
      isValid = false;
    } else {
      setEmailError('');
    }

    return isValid;
  };

  // Check if Next button should be disabled
  const isNextDisabled = (): boolean => {
    switch (currentStep) {
      case 1:
        return !name.trim() || !email.trim() || !validateEmail(email);
      case 2:
        return !satisfaction;
      default:
        return false;
    }
  };

  // Handle Next button
  const handleNext = (): void => {
    if (currentStep === 1 && !isStep1Valid()) {
      return;
    }
    if (currentStep < 5) {
      setCurrentStep(currentStep + 1);
    }
  };

  // Handle Back button
  const handleBack = (): void => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  // Handle feature toggle
  const handleFeatureToggle = (feature: string): void => {
    setSelectedFeatures((prev) =>
      prev.includes(feature)
        ? prev.filter((f) => f !== feature)
        : [...prev, feature]
    );
  };

  // Handle form submission
  const handleSubmit = (): void => {
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction: parseInt(satisfaction, 10),
      features: selectedFeatures,
      comments: comments.trim(),
    });
  };

  // Convert satisfaction index to 1-5 scale
  const satisfactionIndex = satisfaction ? parseInt(satisfaction, 10) : -1;
  const satisfactionLabel = satisfactionIndex >= 0 && satisfactionIndex < props.satisfactionLabels.length
    ? props.satisfactionLabels[satisfactionIndex]
    : '';

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)" align="center">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-4)" align="center">
          <Heading level={2} align="center">Multi-Step Survey</Heading>
          <Text variant="bodySmall" align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {currentStep} of 4
          </Text>
        </Stack>

        {/* Progress Bar */}
        <Box style={{ width: '100%', maxWidth: '600px' }}>
          <Progress
            value={(currentStep / 4) * 100}
            max={100}
            variant="default"
            size="md"
          />
        </Box>

        {/* Form Content */}
        <Card padding="var(--ggui-spacing-8)" shadow="md" style={{ width: '100%', maxWidth: '600px' }}>
          <Stack gap="var(--ggui-spacing-6)">

            {/* Step 1: Name and Email */}
            {currentStep === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Input
                  label="Name"
                  placeholder="Enter your name"
                  value={name}
                  onChange={setName}
                  error={nameError}
                  required
                />
                <Input
                  label="Email"
                  type="email"
                  placeholder="Enter your email"
                  value={email}
                  onChange={setEmail}
                  error={emailError}
                  required
                />
              </Stack>
            )}

            {/* Step 2: Satisfaction Rating */}
            {currentStep === 2 && (
              <RadioGroup
                label="How satisfied are you with our service?"
                value={satisfaction}
                onChange={setSatisfaction}
                options={props.satisfactionLabels.map((label, index) => ({
                  value: String(index),
                  label: label,
                }))}
                direction="vertical"
              />
            )}

            {/* Step 3: Feature Interests */}
            {currentStep === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Which features interest you?</Heading>
                <Stack gap="var(--ggui-spacing-3)">
                  {props.featureOptions.map((feature) => (
                    <Checkbox
                      key={feature}
                      label={feature}
                      checked={selectedFeatures.includes(feature)}
                      onChange={() => handleFeatureToggle(feature)}
                    />
                  ))}
                </Stack>
              </Stack>
            )}

            {/* Step 4: Comments */}
            {currentStep === 4 && (
              <Stack gap="var(--ggui-spacing-4)">
                <TextArea
                  label="Additional Comments"
                  placeholder="Share any additional feedback (optional)"
                  value={comments}
                  onChange={setComments}
                  rows={6}
                  maxLength={500}
                  showCount
                />
              </Stack>
            )}

            {/* Step 5: Review */}
            {currentStep === 5 && (
              <Stack gap="var(--ggui-spacing-6)">
                <Heading level={3} align="center">Review Your Answers</Heading>
                <Divider />
                <Stack gap="var(--ggui-spacing-4)">
                  <div>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name</Text>
                    <Text variant="body" style={{ marginTop: 'var(--ggui-spacing-1)' }}>{name}</Text>
                  </div>
                  <div>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email</Text>
                    <Text variant="body" style={{ marginTop: 'var(--ggui-spacing-1)' }}>{email}</Text>
                  </div>
                  <div>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Satisfaction</Text>
                    <Text variant="body" style={{ marginTop: 'var(--ggui-spacing-1)' }}>{satisfactionLabel}</Text>
                  </div>
                  <div>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Features of Interest</Text>
                    <Stack gap="var(--ggui-spacing-2)" style={{ marginTop: 'var(--ggui-spacing-1)' }}>
                      {selectedFeatures.length > 0 ? (
                        selectedFeatures.map((feature) => (
                          <Badge key={feature} variant="primary" size="sm">{feature}</Badge>
                        ))
                      ) : (
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">None selected</Text>
                      )}
                    </Stack>
                  </div>
                  {comments && (
                    <div>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Comments</Text>
                      <Text variant="body" style={{ marginTop: 'var(--ggui-spacing-1)', whiteSpace: 'pre-wrap' }}>{comments}</Text>
                    </div>
                  )}
                </Stack>
              </Stack>
            )}

          </Stack>
        </Card>

        {/* Navigation Buttons */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-4)" justify="center">
          {currentStep > 1 && (
            <Button variant="ghost" onClick={handleBack}>
              Back
            </Button>
          )}
          {currentStep < 5 && (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={isNextDisabled()}
            >
              Next
            </Button>
          )}
          {currentStep === 5 && (
            <Button variant="primary" onClick={handleSubmit}>
              Submit
            </Button>
          )}
        </Stack>
      </Stack>
    </Container>
  );
}

