// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // Local state for tasks (merged with stream updates)
  const [localTasks, setLocalTasks] = useState(props.tasks);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [addingColumnId, setAddingColumnId] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [newTaskAssignee, setNewTaskAssignee] = useState('');

  // Sync local tasks with props
  useEffect(() => {
    setLocalTasks(props.tasks);
  }, [props.tasks]);

  // Handle real-time updates from stream
  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (!task || !task.id) return;

      if (action === 'delete') {
        setLocalTasks((prev) => prev.filter((t) => t.id !== task.id));
      } else if (action === 'create') {
        setLocalTasks((prev) => [...prev, task]);
      } else if (action === 'move' || action === 'edit') {
        setLocalTasks((prev) =>
          prev.map((t) => (t.id === task.id ? { ...t, ...task } : t))
        );
      }
    }
  }, [taskChanged.latest]);

  // Get tasks by column
  const tasksByColumn = useMemo(() => {
    const grouped: Record<string, typeof localTasks> = {};
    props.columns.forEach((col) => {
      grouped[col.id || ''] = [];
    });
    localTasks.forEach((task) => {
      const colId = task.column || 'todo';
      if (!grouped[colId]) grouped[colId] = [];
      grouped[colId].push(task);
    });
    return grouped;
  }, [localTasks, props.columns]);

  // Calculate totals
  const totalTasks = localTasks.length;
  const completedTasks = localTasks.filter((t) => t.column === 'done').length;

  // Handle task move
  const handleMoveTask = useCallback(
    (taskId: string, newColumn: string) => {
      const task = localTasks.find((t) => t.id === taskId);
      if (task && task.column !== newColumn) {
        setLocalTasks((prev) =>
          prev.map((t) => (t.id === taskId ? { ...t, column: newColumn } : t))
        );
        taskUpdate({
          action: 'move',
          taskId,
          data: { column: newColumn },
        });
      }
    },
    [localTasks, taskUpdate]
  );

  // Handle task edit
  // Handle task edit
  const handleEditTask = useCallback(
    (taskId: string, newTitle: string) => {
      if (newTitle.trim()) {
        setLocalTasks((prev) =>
          prev.map((t) => (t.id === taskId ? { ...t, title: newTitle } : t))
        );
        taskUpdate({
          action: 'edit',
          taskId,
          data: { title: newTitle } as any,
        });
        setEditingTaskId(null);
        setEditingTitle('');
      }
    },
    [taskUpdate]
  );

  // Handle add task
  // Handle add task (always to 'To Do' column)
  const handleAddTask = useCallback(
    () => {
      if (newTaskTitle.trim()) {
        const taskId = `task-${Date.now()}`;
        const newTask = {
          id: taskId,
          title: newTaskTitle,
          priority: newTaskPriority,
          assignee: newTaskAssignee || undefined,
          column: 'todo',
        };
        setLocalTasks((prev) => [...prev, newTask]);
        taskUpdate({
          action: 'create',
          taskId,
          data: { column: 'todo' } as any,
        });
        setNewTaskTitle('');
        setNewTaskPriority('medium');
        setNewTaskAssignee('');
        setAddingColumnId(null);
      }
    },
    [newTaskTitle, newTaskPriority, newTaskAssignee, taskUpdate]
  );

  // Get priority color
  const getPriorityColor = (priority?: string) => {
    switch (priority) {
      case 'high':
        return 'var(--ggui-color-error-500, #ef4444)';
      case 'medium':
        return 'var(--ggui-color-warning-500, #f59e0b)';
      case 'low':
        return 'var(--ggui-color-success-500, #22c55e)';
      default:
        return 'var(--ggui-color-outline, #d4d4d8)';
    }
  };

  // Get priority variant
  const getPriorityVariant = (priority?: string) => {
    switch (priority) {
      case 'high':
        return 'error';
      case 'medium':
        return 'warning';
      case 'low':
        return 'success';
      default:
        return 'default';
    }
  };

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header */}
        <Stack direction="horizontal" align="center" justify="between">
          <Heading level={1}>Task Board</Heading>
          <Box
            paddingX="var(--ggui-spacing-4)"
            paddingY="var(--ggui-spacing-2)"
            background="var(--ggui-color-primary-50, #f0f9ff)"
            borderRadius="var(--ggui-shape-radius-md, 8px)"
          >
