};

export default function Component(props: Props) {
  // State for search and selected element
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][0] | null>(null);

  // Filter elements by search query (case-insensitive)
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const query = searchQuery.toLowerCase();
    return props.elements.filter(el => {
      const name = el.name?.toLowerCase() || '';
      const symbol = el.symbol?.toLowerCase() || '';
      return name.includes(query) || symbol.includes(query);
    });
  }, [searchQuery, props.elements]);

  // Build a map of visible elements for grid positioning
  const visibleElementsMap = useMemo(() => {
    const map = new Map();
    filteredElements.forEach(el => {
      if (el.row && el.col) {
        map.set(`${el.row}-${el.col}`, el);
      }
    });
    return map;
  }, [filteredElements]);

  // Get unique categories for legend
  const categories = useMemo(() => {
    const cats = new Set(props.elements.map(el => el.category).filter(Boolean));
    return Array.from(cats).sort();
  }, [props.elements]);

  // Get color for category
  const getCategoryColor = (category?: string) => {
    if (!category) return { bg: 'var(--ggui-color-surface, #ffffff)', text: 'var(--ggui-color-onSurface, #18181b)', border: 'var(--ggui-color-outline, #d4d4d8)' };
    return CATEGORY_COLORS[category.toLowerCase()] || { bg: 'var(--ggui-color-surfaceVariant, #f4f4f5)', text: 'var(--ggui-color-onSurfaceVariant, #52525b)', border: 'var(--ggui-color-outline, #d4d4d8)' };
  };

  return (
    <Container maxWidth="100%" padding="0">
      <Stack direction="vertical" gap={parseInt('var(--ggui-spacing-6)', 10) || 24}>
        {/* Search Input */}
        <Box paddingX={parseInt('var(--ggui-spacing-6)', 10) || 24} paddingY={parseInt('var(--ggui-spacing-4)', 10) || 16}>
          <SearchField
            value={searchQuery}
            onChange={setSearchQuery}
            placeholder="Search by element name or symbol..."
            size="md"
          />
        </Box>

        {/* Legend */}
        <Box paddingX={parseInt('var(--ggui-spacing-6)', 10) || 24} paddingY={parseInt('var(--ggui-spacing-4)', 10) || 16}>
          <Stack direction="vertical" gap={parseInt('var(--ggui-spacing-2)', 10) || 8}>
            <Heading level={3}>Legend</Heading>
            <Stack direction="horizontal" gap={parseInt('var(--ggui-spacing-4)', 10) || 16} wrap>
              {categories.map((cat) => {
                const color = getCategoryColor(cat);
                return (
                  <Stack direction="horizontal" gap={parseInt('var(--ggui-spacing-2)', 10) || 8} align="center" key={cat}>
                    <Box
                      padding={parseInt('var(--ggui-spacing-3)', 10) || 12}
                      borderRadius={4}
                      background={color.bg}
                      style={{ border: `2px solid ${color.border}`, width: '24px', height: '24px' }}
                    />
                    <Text variant="bodySmall" color={color.text}>{cat || 'Unknown'}</Text>
                  </Stack>
                );
              })}
            </Stack>
          </Stack>
        </Box>

        {/* Periodic Table Grid */}
        <Box
          paddingX={parseInt('var(--ggui-spacing-6)', 10) || 24}
          paddingY={parseInt('var(--ggui-spacing-4)', 10) || 16}
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: parseInt('var(--ggui-spacing-2)', 10) || 8,
            overflowX: 'auto',
            paddingBottom: parseInt('var(--ggui-spacing-4)', 10) || 16,
          }}
        >
          {filteredElements.map((element) => {
            if (!element.row || !element.col) return null;
            const color = getCategoryColor(element.category);
            return (
              <div
                key={`${element.atomicNumber}`}
                style={{
                  gridRow: element.row,
                  gridColumn: element.col,
                }}
              >
                <Card
                  as={Clickable}
                  onClick={() => setSelectedElement(element)}
                  padding={parseInt('var(--ggui-spacing-2)', 10) || 8}
                  shadow="sm"
                  radius="md"
                  style={{
                    background: color.bg,
                    border: `2px solid ${color.border}`,
                    minHeight: '80px',
                    display: 'flex',
                    flexDirection: 'column',
                    justifyContent: 'space-between',
                    cursor: 'pointer',
                    transition: 'all 200ms ease-in-out',
                  }}
                  hoverStyle={{
                    transform: 'scale(1.05)',
                    boxShadow: 'var(--ggui-shadow-md)',
                  }}
                >
                  <Text variant="overline" color={color.text} size="xs" align="left">
                    {element.atomicNumber}
                  </Text>
                  <Text variant="label" color={color.text} size="xl" weight="bold" align="center">
                    {element.symbol}
                  </Text>
                  <Text variant="caption" color={color.text} size="xs" align="center">
                    {element.name}
                  </Text>
                </Card>
              </div>
            );
          })}
        </Box>

        {/* Detail Panel */}
        {selectedElement && (
          <Box paddingX={parseInt('var(--ggui-spacing-6)', 10) || 24} paddingY={parseInt('var(--ggui-spacing-4)', 10) || 16}>
            <Card shadow="md" padding={parseInt('var(--ggui-spacing-6)', 10) || 24} radius="lg">
              <Stack direction="vertical" gap={parseInt('var(--ggui-spacing-4)', 10) || 16}>
                <Stack direction="horizontal" justify="between" align="center">
                  <Heading level={2}>{selectedElement.name}</Heading>
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => setSelectedElement(null)}
                  >
                    ✕
                  </Button>
                </Stack>
                <Divider />
                <Stack direction="vertical" gap={parseInt('var(--ggui-spacing-3)', 10) || 12}>
                  <Stack direction="horizontal" justify="between">
                    <Text variant="label">Symbol:</Text>
                    <Text variant="body" weight="semibold" color="var(--ggui-color-primary-600, #0284c7)">{selectedElement.symbol}</Text>
                  </Stack>
                  <Stack direction="horizontal" justify="between">
                    <Text variant="label">Atomic Number:</Text>
