                  </Stack>
                  <Stack direction="horizontal" justify="between">
                    <Text variant="label">Atomic Weight:</Text>
                    <Text variant="body" weight="semibold">{selectedElement.atomicWeight?.toFixed(2) || 'N/A'}</Text>
                  </Stack>
                  <Stack direction="horizontal" justify="between">
                    <Text variant="label">Category:</Text>
                    <Badge variant="primary" size="sm">{selectedElement.category || 'Unknown'}</Badge>
                  </Stack>
                </Stack>
              </Stack>
            </Card>
          </Box>
        )}
      </Stack>
    </Container>
  );
}

