interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State
  const [messageText, setMessageText] = useState('');
  const [allMessages, setAllMessages] = useState(props.messages);
  const [typingUser, setTypingUser] = useState<string | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when messages change
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [allMessages]);

  // Handle incoming messages from stream
  useEffect(() => {
    if (message.latest) {
      setAllMessages((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Handle typing indicator from stream
  useEffect(() => {
    if (typing.latest) {
      if (typing.latest.active) {
        setTypingUser(typing.latest.sender || 'Someone');
      } else {
        setTypingUser(null);
      }
    }
  }, [typing.latest]);

  // Handle send message
  const handleSendMessage = useCallback(() => {
    if (messageText.trim()) {
      sendMessage({ text: messageText, timestamp: new Date().toISOString() });
      setMessageText('');
    }
  }, [messageText, sendMessage]);

  // Handle Enter key
  const handleKeyDown = useCallback((e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  }, [handleSendMessage]);

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-6)">
      <Card shadow="md" padding="0" radius="lg" style={{ display: 'flex', flexDirection: 'column', height: '600px' }}>
        {/* Header */}
        <Box paddingX="var(--ggui-spacing-6)" paddingY="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant, #f4f4f5)" style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}>
          <Stack direction="horizontal" justify="between" align="center" gap="var(--ggui-spacing-4)">
            <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-4)">
              <Heading level={3}>{props.title}</Heading>
              <Badge variant="primary" size="sm">
                {props.participantCount} participants
              </Badge>
            </Stack>
            {typingUser && (
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {typingUser} is typing...
              </Text>
            )}
          </Stack>
        </Box>

        {/* Messages */}
        <Box
          style={{
            flex: 1,
            overflowY: 'auto',
            padding: 'var(--ggui-spacing-6)',
            display: 'flex',
            flexDirection: 'column',
            gap: 'var(--ggui-spacing-4)',
            background: 'var(--ggui-color-surface, #ffffff)',
          }}
        >
          {allMessages.length === 0 ? (
            <Box
              style={{
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                flex: 1,
              }}
            >
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                No messages yet. Start the conversation!
              </Text>
            </Box>
          ) : (
            <>
              {allMessages.map((msg, idx) => {
                const isCurrentUser = msg.sender === props.currentUser;
                const showAvatar = !isCurrentUser && (idx === 0 || allMessages[idx - 1]?.sender !== msg.sender);
                return (
                  <Box key={idx} style={{ display: 'flex', justifyContent: isCurrentUser ? 'flex-end' : 'flex-start', alignItems: 'flex-end', gap: 'var(--ggui-spacing-2)' }}>
                    {!isCurrentUser && showAvatar && <Avatar name={msg.sender || 'User'} size="sm" />}
                    {!isCurrentUser && !showAvatar && <div style={{ width: '32px' }} />}
                    <Box
                      background={isCurrentUser ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
                      borderRadius="var(--ggui-shape-radius-lg, 12px)"
                      padding="var(--ggui-spacing-4)"
                      style={{ maxWidth: '60%', wordBreak: 'break-word' }}
                    >
                      {!isCurrentUser && msg.sender && (
                        <Text variant="label" color={isCurrentUser ? '#ffffff' : 'var(--ggui-color-onSurfaceVariant, #52525b)'} style={{ marginBottom: 'var(--ggui-spacing-1)' }}>
                          {msg.sender}
                        </Text>
                      )}
                      <Text
                        variant="body"
                        color={isCurrentUser ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}
                      >
                        {msg.text}
                      </Text>
                      {msg.timestamp && (
                        <Text
                          variant="caption"
                          color={isCurrentUser ? 'rgba(255, 255, 255, 0.7)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                          style={{ marginTop: 'var(--ggui-spacing-1)' }}
                        >
                          {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                        </Text>
                      )}
                    </Box>
                  </Box>
                );
              })}
              <div ref={messagesEndRef} />
            </>
          )}
        </Box>

        {/* Input Area */}
        <Box paddingX="var(--ggui-spacing-6)" paddingY="var(--ggui-spacing-4)" style={{ borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)', background: 'var(--ggui-color-surface, #ffffff)' }}>
          <Stack direction="horizontal" gap="var(--ggui-spacing-4)" align="end">
            <TextArea
              label="Message"
              placeholder="Type your message... (Shift+Enter for newline)"
              value={messageText}
              onChange={setMessageText}
              onKeyDown={handleKeyDown}
              rows={2}
              style={{ flex: 1 }}
            />
            <Button
              variant="primary"
              onClick={handleSendMessage}
              disabled={!messageText.trim()}
              rightIcon={<Icon name="send" size={16} />}
            >
              Send
            </Button>
          </Stack>
        </Box>
      </Card>
    </Container>
  );
}
}

