import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State: merge live updates with initial stock data
  const [stocks, setStocks] = useState(props.stocks || []);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [highlightedSymbols, setHighlightedSymbols] = useState<Set<string>>(new Set());

  // Handle incoming price updates from stream and update timestamp
  useEffect(() => {
    if (priceUpdate.latest) {
      setStocks((prevStocks) => {
        const updated = prevStocks.map((stock) => {
          if (stock.symbol === priceUpdate.latest?.symbol) {
            return {
              ...stock,
              price: priceUpdate.latest.price ?? stock.price,
              change: priceUpdate.latest.change ?? stock.change,
              changePercent: priceUpdate.latest.changePercent ?? stock.changePercent,
            };
          }
          return stock;
        });
        return updated;
      });

      // Highlight the updated stock for visual feedback
      setHighlightedSymbols((prev) => new Set([...(prev || []), priceUpdate.latest?.symbol || '']));
      setTimeout(() => {
        setHighlightedSymbols((prev) => {
          const next = new Set(prev);
          next.delete(priceUpdate.latest?.symbol || '');
          return next;
        });
      }, 1000);

      // Update timestamp when price data arrives
      setLastUpdated(new Date());
    }
  }, [priceUpdate.latest]);

  // Format price to 2 decimals
  const formatPrice = (price: number | undefined): string => {
    if (price === undefined) return 'N/A';
    return price.toFixed(2);
  };

  // Determine color based on change
  const getChangeColor = (change: number | undefined): string => {
    if (change === undefined) return 'var(--ggui-color-onSurfaceVariant, #52525b)';
    return change >= 0 ? 'var(--ggui-color-success-600, #16a34a)' : 'var(--ggui-color-error-600, #dc2626)';
  };

  // Format last updated timestamp
  const formatTimestamp = (): string => {
    return lastUpdated.toLocaleTimeString('en-US', {
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
      hour12: true,
    });
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap={24} direction="vertical">
        {/* Header with title and last updated timestamp */}
        <Box
          paddingX="var(--ggui-spacing-4)"
          paddingY="var(--ggui-spacing-4)"
          background="var(--ggui-color-primary-50, #f0f9ff)"
          borderRadius={8}
          style={{
            borderBottom: '2px solid var(--ggui-color-primary-200, #bae6fd)',
          }}
        >
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={1} color="var(--ggui-color-primary-900, #0c4a6e)">
              Market Watch
            </Heading>
            <Stack direction="horizontal" align="center" gap={8}>
              <Text variant="caption" color="var(--ggui-color-primary-700, #0369a1)">
                Last Updated:
              </Text>
              <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)" weight="semibold">
                {formatTimestamp()}
              </Text>
            </Stack>
          </Stack>
        </Box>

        {/* Market status badge */}
        {marketStatus.latest && (
          <Box paddingX="var(--ggui-spacing-4)" paddingY="var(--ggui-spacing-2)">
            <Badge variant={marketStatus.latest.status === 'open' ? 'success' : 'warning'}>
              Market {marketStatus.latest.status?.toUpperCase() || 'UNKNOWN'}
            </Badge>
          </Box>
        )}
        <CardGrid columns={{ sm: 1, md: 1, lg: 3 }} gap={24}>
          {stocks && stocks.length > 0 ? (
            stocks.map((stock) => {
              const changeColor = getChangeColor(stock.change);
              const isHighlighted = highlightedSymbols.has(stock.symbol || '');
              const arrowIcon = (stock.change ?? 0) >= 0 ? '▲' : '▼';

              return (
                <Card
                  key={stock.symbol}
                  padding="var(--ggui-spacing-6)"
                  shadow="md"
                  radius="lg"
                  style={{
                    borderLeft: `4px solid ${changeColor}`,
                    borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                    transition: 'all 200ms ease-in-out',
                    opacity: isHighlighted ? 0.8 : 1,
                    transform: isHighlighted ? 'scale(1.02)' : 'scale(1)',
                    boxShadow: isHighlighted
                      ? '0 10px 25px -5px rgba(0, 0, 0, 0.15)'
                      : 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))',
                  }}
                >
                  <Stack direction="vertical" gap={16}>
                    {/* Ticker Symbol - Large and Bold */}
                    <Text
                      variant="overline"
                      size="3xl"
                      weight="bold"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      {stock.symbol || 'N/A'}
                    </Text>

                    {/* Company Name */}
                    <Text
                      variant="bodySmall"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    >
                      {stock.name || 'Unknown Company'}
                    </Text>

                    <Divider margin={8} />

                    {/* Current Price */}
                    <Stack direction="horizontal" align="center" gap={8}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Price:
                      </Text>
                      <Text
                        variant="bodyLarge"
                        weight="semibold"
                        color="var(--ggui-color-onSurface, #18181b)"
                      >
                        ${formatPrice(stock.price)}
                      </Text>
                    </Stack>

                    {/* Change Amount and Percentage */}
                    <Stack direction="horizontal" align="center" gap={8}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Change:
                      </Text>
                        <Stack direction="horizontal" align="center" gap={4}>
                        <Text
                          variant="body"
                          weight="semibold"
                          color={changeColor}
                        >
                          {stock.change !== undefined ? (stock.change >= 0 ? '+' : '') + stock.change.toFixed(2) : 'N/A'}
                        </Text>
                        <Text
                          variant="body"
                          weight="semibold"
                          color={changeColor}
                        >
                          ({stock.changePercent !== undefined ? (stock.changePercent >= 0 ? '+' : '') + stock.changePercent.toFixed(2) : 'N/A'}%)
                        </Text>
                        <Text
                          variant="body"
                          weight="bold"
                          color={changeColor}
                          size="lg"
                        >
                          {arrowIcon}
                        </Text>
                      </Stack>
                    </Stack>
                  </Stack>
                </Card>
              );
            })
          ) : (
            <Card padding="var(--ggui-spacing-8)" shadow="sm">
              <Text align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                No stocks available
              </Text>
            </Card>
          )}
        </CardGrid>
      </Stack>
    </Container>
  );
}

