  // Email validation regex
  const isValidEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  // Validate current step
  const validateStep = (step: number): boolean => {
    const newErrors: Record<string, string> = {};

    if (step === 1) {
      if (!formData.name.trim()) {
        newErrors.name = 'Name is required';
      }
      if (!formData.email.trim()) {
        newErrors.email = 'Email is required';
      } else if (!isValidEmail(formData.email)) {
        newErrors.email = 'Please enter a valid email address';
      }
      if (!formData.avatar) {
        newErrors.avatar = 'Please select an avatar';
      }
    } else if (step === 2) {
      if (!formData.role) {
        newErrors.role = 'Please select a role';
      }
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  // Handle next step
  const handleNext = () => {
    if (validateStep(currentStep)) {
      setCurrentStep(currentStep + 1);
    }
  };

  // Handle back step
  const handleBack = () => {
    setCurrentStep(currentStep - 1);
    setErrors({});
  };

  // Handle form submission
  const handleComplete = () => {
    complete({
      name: formData.name,
      email: formData.email,
      avatar: formData.avatar,
      role: formData.role,
      emailNotifications: formData.emailNotifications,
      theme: formData.theme,
    });
  };

  // Compute progress percentage
  const progressPercentage = (currentStep / 3) * 100;

  return (
    <Container maxWidth="sm" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)" align="center">
        {/* Step Indicator */}
        <Stack gap="var(--ggui-spacing-4)" align="center" style={{ width: '100%' }}>
          <Badge variant="default" size="md">
            Step {currentStep} of 3
          </Badge>
          <Progress value={progressPercentage} max={100} variant="primary" size="md" />
        </Stack>

        {/* Step 1: Profile Setup */}
        {currentStep === 1 && (
          <Card padding="var(--ggui-spacing-8)" shadow="md" style={{ width: '100%' }}>
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={3}>Profile Setup</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                Let's start by setting up your profile information.
              </Text>

              {/* Name Input */}
              <Input
                label="Full Name"
                placeholder="John Doe"
                value={formData.name}
                onChange={(value) => {
                  setFormData({ ...formData, name: value });
                  if (errors.name) setErrors({ ...errors, name: '' });
                }}
                error={errors.name}
                required
              />

              {/* Email Input */}
              <Input
                label="Email Address"
                type="email"
                placeholder="john@example.com"
                value={formData.email}
                onChange={(value) => {
                  setFormData({ ...formData, email: value });
                  if (errors.email) setErrors({ ...errors, email: '' });
                }}
                error={errors.email}
                required
              />

              {/* Avatar Selection */}
              <Stack gap="var(--ggui-spacing-4)">
                <Text variant="label" style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}>
                  Choose Avatar {errors.avatar && <Text variant="caption" style={{ color: 'var(--ggui-color-error-500)' }}>{errors.avatar}</Text>}
                </Text>
                <Stack direction="horizontal" gap="var(--ggui-spacing-4)" align="center" justify="start">
                  {props.avatarOptions.map((emoji) => (
                    <Box
                      key={emoji}
                      as={Clickable}
                      onClick={() => {
                        setFormData({ ...formData, avatar: emoji });
                        if (errors.avatar) setErrors({ ...errors, avatar: '' });
                      }}
                      style={{
                        fontSize: '2.5rem',
                        padding: 'var(--ggui-spacing-2)',
                        borderRadius: 'var(--ggui-shape-radius-lg)',
                        border: formData.avatar === emoji
                          ? '3px solid var(--ggui-color-primary-600)'
                          : '3px solid var(--ggui-color-outline)',
                        cursor: 'pointer',
                        transition: 'all 200ms ease-in-out',
                      }}
                      hoverStyle={{
                        backgroundColor: 'var(--ggui-color-primary-50)',
                        borderColor: 'var(--ggui-color-primary-400)',
                      }}
                    >
                      {emoji}
                    </Box>
                  ))}
                </Stack>
              </Stack>

              {/* Navigation Buttons */}
              <Stack direction="horizontal" gap="var(--ggui-spacing-4)" justify="end" style={{ width: '100%', marginTop: 'var(--ggui-spacing-4)' }}>
                <Button variant="secondary" onClick={handleNext} disabled={!formData.name.trim() || !formData.email.trim() || !isValidEmail(formData.email)}>
                  Next
                </Button>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 2: Preferences */}
        {currentStep === 2 && (
          <Card padding="var(--ggui-spacing-8)" shadow="md" style={{ width: '100%' }}>
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={3}>Preferences</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                Customize your experience with these preferences.
              </Text>

              {/* Role Selection */}
              <Select
                label="Role"
                value={formData.role}
                onChange={(value) => {
                  setFormData({ ...formData, role: value });
                  if (errors.role) setErrors({ ...errors, role: '' });
                }}
                options={props.roleOptions.map((role) => ({
                  value: role,
                  label: role,
                }))}
                placeholder="Select a role"
                error={errors.role}
                required
              />

              {/* Email Notifications Toggle */}
              <Toggle
                label="Enable Email Notifications"
                checked={formData.emailNotifications}
                onChange={(checked) => setFormData({ ...formData, emailNotifications: checked })}
              />

              {/* Theme Toggle */}
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label" style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}>
                  Theme Preference
                </Text>
                <Stack direction="horizontal" gap="var(--ggui-spacing-4)">
                  <Button
                    variant={formData.theme === 'light' ? 'secondary' : 'outline'}
                    size="sm"
                    onClick={() => setFormData({ ...formData, theme: 'light' })}
                  >
                    Light
                  </Button>
                  <Button
                    variant={formData.theme === 'dark' ? 'secondary' : 'outline'}
                    size="sm"
                    onClick={() => setFormData({ ...formData, theme: 'dark' })}
                  >
                    Dark
                  </Button>
                </Stack>
              </Stack>

              {/* Navigation Buttons */}
              <Stack direction="horizontal" gap="var(--ggui-spacing-4)" justify="between" style={{ width: '100%', marginTop: 'var(--ggui-spacing-4)' }}>
                <Button variant="ghost" onClick={handleBack}>
                  Back
                </Button>
                <Button variant="secondary" onClick={handleNext} disabled={!formData.role}>
                  Next
                </Button>
              </Stack>
            </Stack>
          </Card>

        {/* Step 3: Review & Confirm */}
        {currentStep === 3 && (
          <Card padding="var(--ggui-spacing-8)" shadow="md" style={{ width: '100%' }}>
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={3}>Review & Confirm</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                Please review your information before completing setup.
              </Text>

              {/* Summary Card */}
              <Box
                background="var(--ggui-color-surfaceVariant)"
                borderRadius="var(--ggui-shape-radius-lg)"
                padding="var(--ggui-spacing-4)"
              >
                <Stack gap="var(--ggui-spacing-4)">
                  {/* Name Summary */}
                  <Stack direction="horizontal" gap="var(--ggui-spacing-4)" justify="between" align="center">
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label" style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}>
                        Name
                      </Text>
                      <Text variant="body">{formData.name}</Text>
                    </Stack>
                  </Stack>

                  <Divider margin="var(--ggui-spacing-2)" />

                  {/* Email Summary */}
                  <Stack direction="horizontal" gap="var(--ggui-spacing-4)" justify="between" align="center">
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label" style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}>
                        Email
                      </Text>
                      <Text variant="body">{formData.email}</Text>
                    </Stack>
                  </Stack>

                  <Divider margin="var(--ggui-spacing-2)" />

                  {/* Avatar Summary */}
                  <Stack direction="horizontal" gap="var(--ggui-spacing-4)" justify="between" align="center">
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label" style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}>
                        Avatar
                      </Text>
                    </Stack>
                    <Text style={{ fontSize: '2rem' }}>{formData.avatar}</Text>
                  </Stack>

                  <Divider margin="var(--ggui-spacing-2)" />

                  {/* Role Summary */}
                  <Stack direction="horizontal" gap="var(--ggui-spacing-4)" justify="between" align="center">
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label" style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}>
                        Role
                      </Text>
                      <Text variant="body">{formData.role}</Text>
                    </Stack>
                  </Stack>

                  <Divider margin="var(--ggui-spacing-2)" />

                  {/* Email Notifications Summary */}
                  <Stack direction="horizontal" gap="var(--ggui-spacing-4)" justify="between" align="center">
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label" style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}>
                        Email Notifications
                      </Text>
                      <Badge variant={formData.emailNotifications ? 'success' : 'default'} size="sm">
                        {formData.emailNotifications ? 'Enabled' : 'Disabled'}
                      </Badge>
                    </Stack>
                  </Stack>

                  <Divider margin="var(--ggui-spacing-2)" />

                  {/* Theme Summary */}
                  <Stack direction="horizontal" gap="var(--ggui-spacing-4)" justify="between" align="center">
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label" style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}>
                        Theme
                      </Text>
                       <Badge variant="default" size="sm">
                         {formData.theme === 'light' ? 'Light' : 'Dark'}
                       </Badge>
                    </Stack>
                  </Stack>
                </Stack>
              </Box>

              {/* Navigation Buttons */}
              <Stack direction="horizontal" gap="var(--ggui-spacing-4)" justify="between" style={{ width: '100%', marginTop: 'var(--ggui-spacing-4)' }}>
                <Button variant="ghost" onClick={handleBack}>
                  Go Back
                </Button>
                <Button variant="primary" onClick={handleComplete}>
                  Complete Setup
                </Button>
              </Stack>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}
